1350	func (m *Multipath) handleInbound(ps *peerPathState, raw []byte, srcAP netip.AddrPort) {
1351		fr, err := ps.codec.Decode(raw)
1352		if err != nil {
1353			return // drop malformed / PSK-mismatched outer frames
1354		}
1355		m.dispatchInbound(ps, fr, raw, srcAP)
1356	}
1357	
1358	// demuxInbound is the readLoop's per-frame entry on a (possibly shared) socket: it resolves
1359	// which bound peer's view owns the datagram, then hands the frame to handleInbound on THAT
1360	// view (T88). Because the readLoop holds only the PRIMARY's view of a shared socket (one
1361	// reader per socket), the routing that a concentrator needs — a datagram from peer B decoded
1362	// and resequenced under peer B's plane — happens HERE, not by trusting the reader's own view.
1363	//
1364	// Fast path: a socket with a single peer view (the edge/hub, or any socket not shared by a
1365	// second peer) needs no demux — dispatch on the reader's own view, byte-identical to the
1366	// pre-concentrator behaviour. The per-socket view snapshot is read lock-free; a nil/one-entry
1367	// snapshot means "not a shared concentrator socket".
1368	//
1369	// Shared socket (>1 view):
1370	//   - A source already bound by a prior authenticated PROBE routes straight to that peer's
1371	//     view of THIS socket (one lock-free map Load). A frame that does not verify under that
1372	//     peer's psk — a spoofed source it cannot forge the MAC for — is dropped by handleInbound.
1373	//   - An unbound source is trial-decoded against each peer's psk-derived codec (O(peers),
1374	//     bounded by the static peer count). Only an authenticated PROBE establishes a binding
1375	//     (D9/D11: bindings, like remotes, are learned only from authenticated PROBEs), and a
1376	//     PROBE's MAC verifies under EXACTLY ONE psk — so the FIRST psk whose codec yields a PROBE
1377	//     identifies the peer, binds the source, dispatches, and the loop STOPS there. A non-PROBE
1378	//     decode does NOT stop the trial: DATA/PARITY carry no MAC and are forgeable by design, so
1379	//     a genuine PROBE from a later peer can cross-psk-garble into a DATA/PARITY kind under an
1380	//     earlier peer's codec (~0.4%); the loop must therefore `continue` past a non-PROBE decode
1381	//     to give every remaining psk its chance to authenticate a PROBE. A non-PROBE decode
1382	//     carries no binding authority and is dropped either way — a genuine DATA/PARITY from a
1383	//     not-yet-bound source never dispatches or binds until that peer's PROBE binds it, so
1384	//     continuing past it changes nothing for genuine frames. A forged/garbage frame verifies
1385	//     as a PROBE under NO psk, binds nothing, and is dropped cheaply.
1386	func (m *Multipath) demuxInbound(ps *peerPathState, raw []byte, srcAP netip.AddrPort) {
1387		views := ps.views.Load()
1388		if views == nil || len(*views) <= 1 {
1389			m.handleInbound(ps, raw, srcAP)
1390			return
1391		}
1392		if bound, ok := m.lookupPeerBySource(srcAP.Addr()); ok {
1393			for _, v := range *views {
1394				if v.peer == bound {
1395					m.handleInbound(v, raw, srcAP)
1396					return
1397				}
1398			}
1399			return // the bound peer holds no view of this socket (removed): drop
1400		}
1401		for _, v := range *views {
1402			fr, err := v.codec.Decode(raw)
1403			if err != nil {
1404				continue // not this peer's psk — try the next
1405			}
1406			if _, isProbe := fr.(frame.Probe); !isProbe {
1407				// Decoded under this psk but not a PROBE (DATA/PARITY carry no MAC, so
1408				// this may be a genuine PROBE from a later peer that cross-garbled into an
1409				// unauthenticated kind here). No binding authority: try the remaining psks
1410				// rather than aborting — a genuine unbound DATA/PARITY still never binds.
1411				continue
1412			}
1413			if !m.bindSourceToPeer(srcAP.Addr(), v.peer) {
1414				// Provisional demux state is at its cap (bootstrap flood): drop this new source's
1415				// PROBE rather than grow the map or evict a live binding (Q26/Q27). WG retransmits
1416				// re-drive the bootstrap once a slot frees.
1417				return
1418			}
1419			// The binding just resolved this peer: lazily materialise its heavy receive datapath
1420			// (resequencer ring + FEC decoder buffers) BEFORE dispatch, so a configured peer that
1421			// had never been reached — and a peer whose state was torn down on session loss — pays
1422			// that memory only from its first authenticated binding onward (Q26).
1423			m.ensurePeerReceiveInstantiated(v.peer)
1424			m.dispatchInbound(v, fr, raw, srcAP) // already decoded: dispatch without re-decoding
1425			return
1426		}
1427		// No peer's psk verified: a forged/garbage frame. No binding, drop.
1428	}
1429	
1430	// lookupPeerBySource resolves a learned source address to the peer bound to it, or nil when
1431	// the source is not yet bound. It reads the copy-on-write binding map with a single lock-free
1432	// Load, so the concentrator receive hot path never takes m.mu (see peerBySource).
1433	func (m *Multipath) lookupPeerBySource(addr netip.Addr) (*peerState, bool) {
1434		mp := m.peerBySource.Load()
1435		if mp == nil {
1436			return nil, false
1437		}
1438		p, ok := (*mp)[addr]
1439		return p, ok
1440	}
1441	
1442	// bindSourceToPeer records addr→p in the source-demux map, installed lock-free by a CAS
1443	// republish of a copy with the entry added (T88). It takes NO lock: a reader must never block
1444	// on m.mu (Close waits on the readers WHILE holding m.mu), so the binding — written from a
1445	// readLoop goroutine — must not acquire it. Idempotent: an already-present addr→p binding is a
1446	// no-op, and a lost CAS (a concurrent bind on another socket) simply retries. Copy-on-write
1447	// keeps every published map immutable, so a concurrent lookupPeerBySource over the old snapshot
1448	// is never disturbed.
1449	//
1450	// It returns true when addr is bound to p on return (either freshly installed, already present,
1451	// or re-pointed from another peer — a roam, T90) and false ONLY when the map is at its
1452	// maxDemuxSources cap and addr is a NEW source: drop-on-exhaustion (Q26/Q27). A cap-drop NEVER
1453	// evicts an existing binding, so a live peer is never disturbed by a bootstrap flood; only a
1454	// brand-new source's bootstrap is (temporarily) refused, and WG retransmits cover the gap once
1455	// a slot frees (e.g. a dead peer's teardown). Re-pointing or re-affirming an already-present
1456	// source does not grow the map and is therefore never blocked by the cap.
1457	func (m *Multipath) bindSourceToPeer(addr netip.Addr, p *peerState) bool {
1458		for {
1459			old := m.peerBySource.Load()
1460			var n int
1461			present := false
1462			if old != nil {
1463				existing, ok := (*old)[addr]
1464				if ok {
1465					present = true
1466					if existing == p {
1467						return true // already bound to p: idempotent no-op
1468					}
1469				}
1470				n = len(*old)
1471			}
1472			if !present && m.maxDemuxSources > 0 && n >= m.maxDemuxSources {
1473				// Cap exhausted and this is a NEW source: drop it. An existing (live) binding is
1474				// never evicted to make room — bootstrap degrades, isolation holds.
1475				return false
1476			}
1477			next := make(map[netip.Addr]*peerState, n+1)
1478			if old != nil {
1479				for k, v := range *old {
1480					next[k] = v
1481				}
1482			}
1483			next[addr] = p
1484			if m.peerBySource.CompareAndSwap(old, &next) {
1485				return true
1486			}
1487			// Lost the race with a concurrent bind: reload and retry.
1488		}
1489	}
1490	
1491	// unbindPeerSources removes every source->peer entry pointing at p from the demux map (a CAS
1492	// republish of a copy with p's entries dropped), reclaiming their cap slots so a fresh
1493	// authenticated PROBE can re-bind after the peer is re-instantiated. Like bindSourceToPeer it
1494	// is lock-free copy-on-write (retry on a lost CAS), so it composes with a concurrent bind on a
1495	// readLoop goroutine without either blocking on m.mu. A no-op when p holds no bindings.
1496	func (m *Multipath) unbindPeerSources(p *peerState) {
1497		for {
1498			old := m.peerBySource.Load()
1499			if old == nil {
1500				return
1501			}
1502			found := false
1503			for _, v := range *old {
1504				if v == p {
1505					found = true
1506					break
1507				}
1508			}
1509			if !found {
1510				return
1511			}
1512			next := make(map[netip.Addr]*peerState, len(*old))
1513			for k, v := range *old {
1514				if v != p {
1515					next[k] = v
1516				}
1517			}
1518			if m.peerBySource.CompareAndSwap(old, &next) {
1519				return
1520			}
1521		}
1522	}
1523	
1524	// peerIsLiveLocked reports whether ANY of peer p's paths is currently StateUp — the liveness
1525	// gate that makes teardown safe: a peer with a live path is actively carrying (or about to
1526	// carry) traffic and must NEVER be torn down (Q26). It reads each path's own immutable prober
1527	// State() (atomic internally, per the PathHealth contract), so it is safe under m.mu. A peer
1528	// with no prober-bearing path (a bind without the probe transport) reports not-live, matching
1529	// the fact that such a bind has no liveness signal to protect.
1530	func (m *Multipath) peerIsLiveLocked(p *peerState) bool {
1531		for _, pp := range p.paths {
1532			if pp.prober != nil && pp.prober.State() == telemetry.StateUp {
1533				return true
1534			}
1535		}
1536		return false
1537	}
1538	
1539	// teardownPeerLocked frees a dead peer's HEAVY per-peer state — the ~2048-frame resequencer
1540	// ring and the FEC send/receive buffers — and releases its source->peer demux bindings,
1541	// reclaiming both the memory and the demux-map cap slots (Q26). It is the lifecycle dual of
1542	// ensurePeerReceiveInstantiated: after teardown the peer is dormant (its light state — psk,
1543	// codec, reflector, per-(peer,path) views — survives so a trial-decode still authenticates it),
1544	// and the next authenticated PROBE re-binds a source and re-instantiates the ring cleanly. It
1545	// REFUSES to tear down a LIVE peer (any path StateUp) and the embedded primary (the edge/hub,
1546	// whose lifecycle is Open/Close, not session teardown), returning false in both cases so a
1547	// caller can distinguish "torn down" from "kept". The heavy fields are atomic.Pointer, so
1548	// Store(nil) is safe against a concurrent readLoop (which nil-guards its Load); the drainer
1549	// likewise skips a peer whose resequencer Loads nil. Caller holds m.mu.
1550	func (m *Multipath) teardownPeerLocked(p *peerState) bool {
1551		if p == m.peerState {
1552			return false // the primary (edge/hub) is torn down only by Close, never by session loss
1553		}
1554		if m.peerIsLiveLocked(p) {
1555			return false // a live (Up) peer is never torn down, whatever other peers' churn
1556		}
1557		// Clear the heavy trio under lifecycleMu so a concurrent ensurePeerReceiveInstantiated on a
1558		// readLoop (which also holds lifecycleMu across its whole build-and-publish) cannot interleave:
1559		// it either runs wholly before this clear (and is then wholly undone here) or wholly after
1560		// (and rebuilds all three cleanly). This closes the resurrection/half-published hole where a
1561		// teardown landing mid-instantiation left a fecRecv/fecSend without its resequencer, which the
1562		// next re-bind then reused stale. lifecycleMu is a leaf lock (see its field doc); we hold m.mu
1563		// here, giving the fixed order m.mu -> lifecycleMu with no cycle. The unbind runs after the
1564		// clear (and outside lifecycleMu): it is its own lock-free CAS loop and needs no ordering here.
1565		p.lifecycleMu.Lock()
1566		p.resequencer.Store(nil)
1567		p.fecRecv.Store(nil)
1568		p.fecSend.Store(nil)
1569		p.lifecycleMu.Unlock()
1570		m.unbindPeerSources(p)
1571		return true
